# Check all page configs for section IDs that might not be in the registry
pages_dir = '/root/nexa-paraguay/nexa-pages'
all_ids = set()
for f in os.listdir(pages_dir):
    if f.endswith('.json'):
        with open(os.path.join(pages_dir, f)) as fp:
            try:
                page = json.load(fp)
                for s in page.get('sections', []):
                    all_ids.add(s.get('id', ''))
            except:
                pass

print("All section IDs used across page configs:")
for sid in sorted(all_ids):
    print(f"  {sid}")

# Check what the registry supports
reg_path = '/root/ai-whisperers-base/packages/sections/src/registry.tsx'
with open(reg_path) as f:
    reg = f.read()

import re
registered = re.findall(r'"([a-z][a-z0-9-]*)":\s*([A-Z][a-zA-Z]+)', reg)
print("\nRegistry mappings:")
for sid, comp in registered:
    print(f"  '{sid}' -> {comp}")

# Find missing
registered_ids = {s for s, c in registered}
missing = all_ids - registered_ids - {'header', 'footer', ''}
print(f"\nMissing from registry: {missing}")

# Also check what header/footer are supposed to be
print("\nAll section IDs in pages:", sorted(all_ids))"}

