for loc in ['es', 'en', 'nl', 'de']:
    with open(f'/root/nexa-paraguay/content/{loc}.json') as f:
        d = json.load(f)

    # Find and strip empty string keys from every object that has them
    def strip_empty(obj, path=''):
        if isinstance(obj, dict):
            # Remove keys with empty string values at the section level
            empty_keys = [k for k, v in obj.items() if v == '' and k not in ('', None)]
            if empty_keys and not any(k.startswith('page') for k in obj.keys()):
                # Only strip from objects that are clearly section content (have real content keys too)
                real_keys = [k for k, v in obj.items() if v != '']
                if len(real_keys) > 0 and len(empty_keys) > len(real_keys):
                    for k in empty_keys:
                        del obj[k]
            # Recurse
            for k, v in obj.items():
                strip_empty(v, f'{path}.{k}')
        elif isinstance(obj, list):
            for item in obj:
                if isinstance(item, (dict, list)):
                    strip_empty(item, path)

    strip_empty(d)
    with open(f'/root/nexa-paraguay/content/{loc}.json', 'w') as f:
        json.dump(d, f, ensure_ascii=False, indent=2)
    print(f"Cleaned {loc}")

    # Verify hero no longer has pollution
    hero = d.get('home', {}).get('hero', {})
    empty = [k for k, v in hero.items() if v == '']
    real = [k for k, v in hero.items() if v != '']
    print(f"  hero: {len(real)} real keys, {len(empty)} empty keys")

print("\nDone.")"}

